import { chmod, copyFile, lstat, mkdir, readFile, writeFile } from 'node:fs/promises';
import path from 'node:path';

import { deepMerge } from '../utils/deep-merge.js';
import { stringifyToml } from '../utils/toml-stringify.js';

export const GENERATED_MARKER = 'Generated by @tanaabased/emori aisync.';

const GENERATED_HEADER = `# ${GENERATED_MARKER}
# Do not edit this file directly. Edit config.shared.toml or config.local.toml instead.

`;

const FORBIDDEN_SHARED_KEYS = new Set([
  'auth',
  'auth_json',
  'chatgpt_base_url',
  'cli_auth_credentials_store',
  'forced_chatgpt_workspace_id',
  'forced_login_method',
  'installation_id',
  'log_dir',
  'marketplaces',
  'mcp_oauth_callback_url',
  'mcp_oauth_credentials_store',
  'mcp_servers',
  'model_catalog_json',
  'notify',
  'openai_base_url',
  'plugin_cache',
  'plugin_cache_path',
  'plugin_path',
  'plugin_paths',
  'plugins',
  'projects',
  'sqlite_home',
]);

const FORBIDDEN_KEY_PATTERNS = [
  /(^|_)(auth|credential|credentials|installation|login|token)($|_)/i,
  /(^|_)(cache|history|log|session|sqlite|state)($|_)/i,
];

function isPlainObject(value) {
  return Object.prototype.toString.call(value) === '[object Object]';
}

async function pathExists(targetPath) {
  try {
    await lstat(targetPath);
    return true;
  } catch {
    return false;
  }
}

function defaultParseToml(content) {
  const parser = globalThis.Bun?.TOML?.parse;
  if (!parser) {
    throw new Error('Bun.TOML.parse is required to parse Codex config TOML.');
  }

  return parser(content);
}

async function readTomlFile(targetPath, { parseToml = defaultParseToml, required = false } = {}) {
  if (!(await pathExists(targetPath))) {
    if (required) {
      throw new Error(`Missing required Codex config fragment: ${targetPath}`);
    }

    return {};
  }

  const content = await readFile(targetPath, 'utf8');
  try {
    const parsed = parseToml(content);
    return parsed ?? {};
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    throw new Error(`Could not parse ${targetPath}: ${message}`, { cause: error });
  }
}

function looksLikeLocalPath(value) {
  return /^(\/|~\/|\.\/|\.\.\/|[A-Za-z]:[\\/]|file:\/\/)/.test(value);
}

function formatConfigPath(segments) {
  return segments.join('.');
}

/**
 * Reject shared Codex config keys that encode machine-specific identity, paths,
 * auth, cache, state, or local project data.
 *
 * @param {object} config Parsed shared Codex config.
 * @param {string} sourcePath Path shown in validation failures.
 * @throws {Error} When the shared config contains machine-specific keys or paths.
 */
export function validatePortableSharedConfig(config, sourcePath = 'config.shared.toml') {
  const violations = [];

  function visit(value, segments = []) {
    if (Array.isArray(value)) {
      value.forEach((entry, index) => visit(entry, [...segments, String(index)]));
      return;
    }

    if (!isPlainObject(value)) {
      if (typeof value === 'string' && looksLikeLocalPath(value)) {
        violations.push(`${formatConfigPath(segments)} contains a local path`);
      }

      return;
    }

    for (const [key, entry] of Object.entries(value)) {
      const nextSegments = [...segments, key];
      const normalizedKey = key.toLowerCase();

      if (looksLikeLocalPath(key)) {
        violations.push(`${formatConfigPath(nextSegments)} uses a local path key`);
      }

      if (FORBIDDEN_SHARED_KEYS.has(normalizedKey)) {
        violations.push(`${formatConfigPath(nextSegments)} is machine-specific`);
      }

      if (FORBIDDEN_KEY_PATTERNS.some((pattern) => pattern.test(key))) {
        violations.push(`${formatConfigPath(nextSegments)} looks auth/state/cache-specific`);
      }

      visit(entry, nextSegments);
    }
  }

  visit(config);

  if (violations.length > 0) {
    throw new Error(
      [
        `${sourcePath} must contain only portable global Codex settings.`,
        ...violations.map((violation) => `- ${violation}`),
      ].join('\n'),
    );
  }
}

async function isGeneratedConfig(targetPath) {
  if (!(await pathExists(targetPath))) {
    return false;
  }

  const content = await readFile(targetPath, 'utf8');
  return content.startsWith(`# ${GENERATED_MARKER}`);
}

/**
 * Generate Codex config from portable shared defaults plus optional local
 * overrides.
 *
 * Side effects: reads the shared/local fragments, migrates an unmanaged output
 * file to the local fragment on first run, writes the generated output, and
 * chmods generated files to the supplied private mode.
 *
 * @param {object} options Sync options.
 * @param {string} options.sharedPath Required portable shared config path.
 * @param {string} options.localPath Required machine-local override path.
 * @param {string} options.outputPath Required generated config output path.
 * @param {number} [options.mode=0o600] File mode for migrated and generated config files.
 * @param {(content: string) => object} [options.parseToml] TOML parser override for tests.
 * @returns {Promise<{localPath: string, migratedLocal: boolean, outputPath: string, sharedPath: string}>} Paths used by the sync and whether an unmanaged output was migrated.
 * @throws {Error} When required paths are missing, TOML parsing fails, shared config is not portable, or unmanaged config conflicts with existing local config.
 */
export async function syncCodexConfig({
  localPath,
  mode = 0o600,
  outputPath,
  parseToml = defaultParseToml,
  sharedPath,
} = {}) {
  if (!sharedPath || !localPath || !outputPath) {
    throw new Error('sharedPath, localPath, and outputPath are required.');
  }

  const sharedConfig = await readTomlFile(sharedPath, { parseToml, required: true });
  validatePortableSharedConfig(sharedConfig, sharedPath);

  const outputExists = await pathExists(outputPath);
  const localExists = await pathExists(localPath);
  const outputIsGenerated = outputExists ? await isGeneratedConfig(outputPath) : false;

  let migratedLocal = false;
  if (outputExists && !outputIsGenerated) {
    if (localExists) {
      throw new Error(
        `${outputPath} is not generated and ${localPath} already exists. Reconcile them before running aisync.`,
      );
    }

    await mkdir(path.dirname(localPath), { recursive: true });
    await copyFile(outputPath, localPath);
    await chmod(localPath, mode);
    migratedLocal = true;
  }

  const localConfig = await readTomlFile(localPath, { parseToml });
  const mergedConfig = deepMerge(sharedConfig, localConfig);
  const rendered = `${GENERATED_HEADER}${stringifyToml(mergedConfig)}`;

  await mkdir(path.dirname(outputPath), { recursive: true });
  await writeFile(outputPath, rendered, { mode });
  await chmod(outputPath, mode);

  return {
    localPath,
    migratedLocal,
    outputPath,
    sharedPath,
  };
}
